import React from "react";
import { Link } from "react-router-dom";
import { pluralize } from "../../utils/helpers"
import { useStoreContext } from "../../utils/GlobalState";
import { ADD_TO_CART, UPDATE_CART_QUANTITY } from "../../utils/actions";
import { idbPromise } from "../../utils/helpers";
import Button from 'react-bootstrap/Button';
import Card from 'react-bootstrap/Card';
import Stack from 'react-bootstrap/Stack';
import Row from 'react-bootstrap/Row';
import Container from 'react-bootstrap/Container';
import Nav from 'react-bootstrap/Nav';
import NavDropdown from 'react-bootstrap/NavDropdown';
import Image from 'react-bootstrap/Image'



function ProductItem(item) {
  const [state, dispatch] = useStoreContext();

  const {
    image,
    name,
    _id,
    price,
    quantity,
    description,
  } = item;

  const { cart } = state

  const addToCart = () => {
    const itemInCart = cart.find((cartItem) => cartItem._id === _id)
    if (itemInCart) {
      dispatch({
        type: UPDATE_CART_QUANTITY,
        _id: _id,
        purchaseQuantity: parseInt(itemInCart.purchaseQuantity) + 1
      });
      idbPromise('cart', 'put', {
        ...itemInCart,
        purchaseQuantity: parseInt(itemInCart.purchaseQuantity) + 1
      });
    } else {
      dispatch({
        type: ADD_TO_CART,
        product: { ...item, purchaseQuantity: 1 }
      });
      idbPromise('cart', 'put', { ...item, purchaseQuantity: 1 });
    }
  }

  const handleSelect = (eventKey) => alert(`selected ${eventKey}`);

  // style={{ display: "flex", flexFlow: "row-wrap", justifyContent: "space-around" }}

  return (
    <>
          {/* <div style={{ display:"flexbox"}}> */}
          <div style={{ margin: "5px"}}>
          <Card style={{ border: "none", background:"lightgrey", width:"auto", maxWidth:"480px", height:"auto" }}>
            <Card.Img variant="top" src={`/images/${image}`} />
            <Card.Body>
              <Card.Title style={{ fontFamily: "Inknut Antiqua" }}> {name} </Card.Title>
              <Card.Text style={{ fontFamily: "Inknut Antiqua", fontStyle: "italic" }}>
                {description}
              </Card.Text>
              <Card.Text style={{ fontStyle: "bold" }}>
                ${price}
              </Card.Text>
            </Card.Body>
            <Container>
              <Row>
              <Stack gap={2} >
                <Button size="med" className="m-auto" onClick={addToCart} style={{ width:"18rem", display:"flex", justifyContent:"center" }} variant="light" > Add To Cart </Button>
                <Button size="med" className="m-auto" onClick={addToCart} style={{ width:"15rem", display:"flex", justifyContent:"center" }} href={`/products/${_id}`} variant="light"> View </Button>
             </Stack>
              </Row>
            </Container>
            <Row> <br /> </Row>
          </Card>
      </div>


      {/* <div className="card px-1 py-1">
        <Link to={`/products/${_id}`}>
          <img
            alt={name}
            src={`/images/${image}`}
          />
          <p>{name}</p>
        </Link>
        <div>
          <div>{quantity} {pluralize("item", quantity)} in stock</div>
          <span>${price}</span>
        </div>
        <button onClick={addToCart}>Add to cart</button>
      </div> */}
    </>
  );
}

export default ProductItem;
